import torch

def heaviside(a, b):
    out = torch.zeros_like(a, dtype=torch.float32)
    for k in range(a.shape[0]):
        if a[k] > 0:
            out[k] = 1
        elif a[k] == 0:
            out[k] = b[k]
        else:
            out[k] = 0
    return out

